export class SoundSystem {
  static propagate(sector: Sector, blocks: number): void {
    if (sector.validCount === validCount) return;
    sector.validCount = validCount;
    sector.soundTarget = soundTarget;
    for (let i = 0; i < sector.lineCount; i++) {
      const line = sector.lines[i];
      if (!(line.flags & ML_TWOSIDED)) continue;
      const other = SoundSystem.getOtherSector(sector, line);
      if (line.flags & ML_SOUNDBLOCK) {
        if (!blocks) SoundSystem.propagate(other, 1);
      } else {
        SoundSystem.propagate(other, blocks);
      }
    }
  }

  static alert(target: MapObject, emitter: MapObject): void {
    soundTarget = target;
    validCount++;
    SoundSystem.propagate(emitter.subsector.sector, 0);
  }
}
